func TestNovelEntitiesResolveSearchesOfficialRecords(t *testing.T) {
	cases := []struct {
		name     string
		query    string
		resource string
		seed     string
		wantKind string
	}{
		{
			name:     "client match",
			query:    "Boeing",
			resource: "clients",
			seed:     `{"id":10,"client_id":"C-10","name":"Boeing Company","url":"https://lda.gov/api/v1/clients/10/"}`,
			wantKind: "client",
		},
		{
			name:     "registrant match",
			query:    "Akin",
			resource: "registrants",
			seed:     `{"id":20,"house_registrant_id":123,"name":"Akin Gump Strauss Hauer & Feld","url":"https://lda.gov/api/v1/registrants/20/"}`,
			wantKind: "registrant",
		},
	}
	for _, tc := range cases {
		t.Run(tc.name, func(t *testing.T) {
			dbPath := newLDANovelTestDB(t)
			seedLDANovelRecord(t, dbPath, tc.resource, tc.resource+"-1", tc.seed)
			flags := &rootFlags{asJSON: true}
			rows := runLDANovelRows(t, newNovelEntitiesResolveCmd(flags), tc.query, "--db", dbPath, "--limit", "5")
			row := requireLDANovelRow(t, rows, "kind", tc.wantKind)
			if row["score"].(float64) < 80 {
				t.Fatalf("score = %v, want strong match in %#v", row["score"], rows)
			}
		})
	}
}

